292				t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
293			}
294			// A の MAX(base+2h) > B の MAX(base+1h) なので A が先頭
295			// （MIN 集約だと A の最古は base となり、B(base+1h) が先頭になる）
