308			cleanupMediumProgresses(ctx, pool)
309	
310			now := time.Now()
311			if err := insertProgress(ctx, pool, mediumTestOtherUser, mediumTestTopicA0ID, now); err != nil {
312				t.Fatalf("progress 挿入失敗: %v", err)
313			}
314	
315			w := httptest.NewRecorder()
316			handler.GetEnrollmentsHandler(w, newGetEnrollmentsRequest(t, mediumTestUserID))
317	
318			var body GetEnrollmentsResponse
319			if err := json.NewDecoder(w.Result().Body).Decode(&body); err != nil {
320				t.Fatalf("レスポンスボディのデコードに失敗しました: %v", err)
321			}
322			if len(body.Enrollments) != 0 {
323				t.Errorf("対象ユーザーの受講中コースが0件であること: got %d", len(body.Enrollments))
324			}
325		})
326	}
