			[]any{mediumTestSectionCID, mediumTestCourseCID},
		},
		{
			`INSERT INTO course_section_topics (course_section_topic_id, course_id, course_section_id, index, title, description, content)
			 VALUES ($1, $2, $3, 0, 'A0', '', '')`,
